import { getManifest } from "@/lib/manifest";
import type { ServiceManifest, Domain } from "@/types/stack";

// ─── Domain colour map ───────────────────────────────────────────────────────
const DOMAIN_COLORS: Record<Domain, string> = {
  commerce:       "bg-emerald-500",
  fleet:          "bg-amber-500",
  iot:            "bg-blue-500",
  crm:            "bg-purple-500",
  ai:             "bg-pink-500",
  marketing:      "bg-orange-500",
  education:      "bg-cyan-500",
  health:         "bg-red-500",
  security:       "bg-indigo-500",
  platform:       "bg-teal-500",
  bi:             "bg-violet-500",
  internal:       "bg-gray-500",
  infrastructure: "bg-gray-400",
};

// ─── Phase display labels ────────────────────────────────────────────────────
const PHASE_LABELS: Record<string, string> = {
  infrastructure: "Infrastructure",
  "1a": "Phase 1A — Commerce, Fleet, CRM, IAM",
  "1b": "Phase 1B — IoT, AI, Education, Health",
  "1c": "Phase 1C — Marketing, Platform, Security",
  "2":  "Phase 2 — Recommended Additions",
};

const PHASE_ORDER = ["infrastructure", "1a", "1b", "1c", "2"];

// ─── Service Card ────────────────────────────────────────────────────────────
function ServiceCard({ svc }: { svc: ServiceManifest }) {
  const domainColor = DOMAIN_COLORS[svc.domain] ?? "bg-gray-500";
  const isHighRisk = svc.riskLevel === "HIGH" || svc.riskLevel === "MEDIUM";

  return (
    <div className="bg-gray-900 border border-gray-800 rounded-lg p-4 flex flex-col gap-3 hover:border-gray-600 transition-colors">
      {/* Top row: name + risk + verdict */}
      <div className="flex items-start justify-between gap-2">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <h3 className="font-bold text-gray-100 text-sm truncate">{svc.name}</h3>
            {isHighRisk && (
              <span
                title={svc.riskNotes ?? `Risk: ${svc.riskLevel}`}
                className="text-yellow-400 text-xs flex-shrink-0"
              >
                ⚠
              </span>
            )}
          </div>
          {svc.role && (
            <p className="text-xs text-gray-400 mt-0.5 truncate">{svc.role}</p>
          )}
          {svc.notes && (
            <p className="text-xs text-gray-500 italic mt-0.5 truncate">{svc.notes}</p>
          )}
        </div>
        <span
          className={`flex-shrink-0 text-xs font-semibold px-2 py-0.5 rounded-full ${
            svc.verdict === "ESSENTIAL"
              ? "bg-green-900 text-green-300 border border-green-700"
              : "bg-amber-900 text-amber-300 border border-amber-700"
          }`}
        >
          {svc.verdict === "ESSENTIAL" ? "ESSENTIAL" : "RECOMMENDED"}
        </span>
      </div>

      {/* Domain badge + port */}
      <div className="flex items-center gap-2 flex-wrap">
        <span
          className={`${domainColor} text-white text-xs font-medium px-2 py-0.5 rounded`}
        >
          {svc.domain}
        </span>
        {svc.defaultPort && (
          <span className="text-xs text-gray-500 font-mono">:{svc.defaultPort}</span>
        )}
        {svc.buildFromSource && (
          <span className="text-xs text-orange-400 border border-orange-800 rounded px-1.5 py-0.5">
            build-from-src
          </span>
        )}
      </div>

      {/* Links */}
      <div className="flex gap-3 mt-auto pt-1 border-t border-gray-800">
        <a
          href={svc.repository}
          target="_blank"
          rel="noopener noreferrer"
          className="text-xs text-blue-400 hover:text-blue-300 transition-colors"
        >
          GitHub ↗
        </a>
        {svc.docsUrl && (
          <a
            href={svc.docsUrl}
            target="_blank"
            rel="noopener noreferrer"
            className="text-xs text-gray-400 hover:text-gray-300 transition-colors"
          >
            Docs ↗
          </a>
        )}
      </div>
    </div>
  );
}

// ─── Main Page (Server Component) ───────────────────────────────────────────
export default function StackPage() {
  const manifest = getManifest();

  const allServices = [...manifest.infrastructure, ...manifest.services];
  const essentialCount = allServices.filter((s) => s.verdict === "ESSENTIAL").length;
  const recommendedCount = allServices.filter((s) => s.verdict === "RECOMMENDED").length;

  // Group by phase
  const byPhase: Record<string, ServiceManifest[]> = {};
  for (const phase of PHASE_ORDER) {
    byPhase[phase] = allServices.filter((s) => s.phase === phase);
  }

  return (
    <div className="min-h-screen bg-gray-950 text-gray-100">
      <div className="max-w-screen-xl mx-auto px-4 sm:px-6 lg:px-8 py-10">

        {/* ── Header ── */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold tracking-tight text-white">
            Hylono Stack
          </h1>
          <p className="mt-1 text-gray-400 text-sm">
            Master implementation plan · {manifest.meta.totalServices} services · v{manifest.meta.version}
          </p>
        </div>

        {/* ── Stats Row ── */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-10">
          <div className="bg-gray-900 border border-gray-800 rounded-lg p-4 text-center">
            <div className="text-2xl font-bold text-white">{manifest.meta.totalServices}</div>
            <div className="text-xs text-gray-400 mt-1 uppercase tracking-wide">Total Services</div>
          </div>
          <div className="bg-gray-900 border border-gray-800 rounded-lg p-4 text-center">
            <div className="text-2xl font-bold text-green-400">{essentialCount}</div>
            <div className="text-xs text-gray-400 mt-1 uppercase tracking-wide">Essential</div>
          </div>
          <div className="bg-gray-900 border border-gray-800 rounded-lg p-4 text-center">
            <div className="text-2xl font-bold text-amber-400">{recommendedCount}</div>
            <div className="text-xs text-gray-400 mt-1 uppercase tracking-wide">Recommended</div>
          </div>
          <div className="bg-gray-900 border border-gray-800 rounded-lg p-4 text-center">
            <div className="text-2xl font-bold text-blue-400">{PHASE_ORDER.length}</div>
            <div className="text-xs text-gray-400 mt-1 uppercase tracking-wide">Phases</div>
          </div>
        </div>

        {/* ── Services grouped by phase ── */}
        {PHASE_ORDER.map((phase) => {
          const services = byPhase[phase];
          if (!services || services.length === 0) return null;
          return (
            <section key={phase} className="mb-10">
              <h2 className="text-lg font-semibold text-gray-200 mb-4 pb-2 border-b border-gray-800">
                {PHASE_LABELS[phase] ?? phase}
                <span className="ml-2 text-sm font-normal text-gray-500">
                  ({services.length} services)
                </span>
              </h2>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {services.map((svc) => (
                  <ServiceCard key={svc.id} svc={svc} />
                ))}
              </div>
            </section>
          );
        })}

        {/* ── Integrations Table ── */}
        <section className="mb-10">
          <h2 className="text-lg font-semibold text-gray-200 mb-4 pb-2 border-b border-gray-800">
            Integration Flows
            <span className="ml-2 text-sm font-normal text-gray-500">
              ({manifest.integrations.length} flows)
            </span>
          </h2>
          <div className="overflow-x-auto rounded-lg border border-gray-800">
            <table className="w-full text-sm text-left">
              <thead className="bg-gray-900 text-gray-400 uppercase text-xs tracking-wide">
                <tr>
                  <th className="px-4 py-3">Source</th>
                  <th className="px-4 py-3">→</th>
                  <th className="px-4 py-3">Target</th>
                  <th className="px-4 py-3">Data</th>
                  <th className="px-4 py-3">Via</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-800">
                {manifest.integrations.map((flow, i) => (
                  <tr
                    key={i}
                    className="bg-gray-900 hover:bg-gray-800 transition-colors"
                  >
                    <td className="px-4 py-2.5 font-mono text-blue-400 text-xs">{flow.source}</td>
                    <td className="px-4 py-2.5 text-gray-600">→</td>
                    <td className="px-4 py-2.5 font-mono text-purple-400 text-xs">{flow.target}</td>
                    <td className="px-4 py-2.5 text-gray-300 text-xs">{flow.data}</td>
                    <td className="px-4 py-2.5 text-gray-500 text-xs">{flow.via}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        {/* ── R&D References ── */}
        <section className="mb-10">
          <h2 className="text-lg font-semibold text-gray-200 mb-4 pb-2 border-b border-gray-800">
            R&amp;D References
            <span className="ml-2 text-sm font-normal text-gray-500">
              ({manifest.rnd.length} projects)
            </span>
          </h2>
          <div className="flex flex-col gap-2">
            {manifest.rnd.map((item) => (
              <div
                key={item.id}
                className="bg-gray-900 border border-gray-800 rounded-lg px-4 py-3 flex items-center gap-4"
              >
                <span className="font-semibold text-gray-200 text-sm w-36 flex-shrink-0">
                  {item.name}
                </span>
                <span className="text-gray-400 text-xs flex-1">{item.description}</span>
                <a
                  href={item.repository}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-xs text-blue-400 hover:text-blue-300 transition-colors flex-shrink-0"
                >
                  GitHub ↗
                </a>
              </div>
            ))}
          </div>
        </section>

        {/* ── Footer ── */}
        <footer className="text-center text-xs text-gray-600 pt-6 border-t border-gray-800">
          Hylono Stack Control Panel · v{manifest.meta.version} · {manifest.meta.totalServices} services
        </footer>
      </div>
    </div>
  );
}
